18	  const itemsBase = step.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 25), 0);
19	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
20	  const premium = Math.ceil(itemsBase + firstInsurance) + PROCESSING_FEE;
21	  return { premium };
22	};
23	
